【高性能JavaScript - 使用requestAnimationFrame确保流畅】
```html
<script>
(function() {
  'use strict';

  // 容器ID已在HTML中生成，直接获取
  const container = document.getElementById('scene-{{timestamp}}');
  if (!container) {
    console.error('[排版师] 找不到场景容器，请检查ID: scene-{{timestamp}}');
    return;
  }

  // 从容器ID中提取场景ID
  const SCENE_ID = container.id;

  // 状态管理
  const state = {
    currentParagraph: 0,
    isTyping: false,
    typewriterDone: false,
    interactionTriggered: false,
    selectedValue: null,
    rafId: null,
    lastTypeTime: 0
  };

  // ===== 健壮性检查：确保必要元素存在 =====
  let textLayer = container.querySelector('.text-layer');
  if (!textLayer) {
    console.warn('[排版师] 未找到.text-layer，动态创建');
    textLayer = document.createElement('div');
    textLayer.className = 'text-layer';
    // 需要插入到 .content-wrapper 内，若不存在则创建
    let contentWrapper = container.querySelector('.content-wrapper');
    if (!contentWrapper) {
      contentWrapper = document.createElement('div');
      contentWrapper.className = 'content-wrapper';
      container.appendChild(contentWrapper);
    }
    contentWrapper.prepend(textLayer);
  }

  let paragraphs = container.querySelectorAll('.text-box');
  if (paragraphs.length === 0) {
    console.warn('[排版师] 未找到.text-box，创建默认段落');
    const defaultBox = document.createElement('div');
    defaultBox.className = 'text-box';
    defaultBox.innerHTML = '<p class="narrative-text" data-fulltext="场景加载中...">场景加载中...</p><div class="continue-wrapper"><span class="continue-hint">▼ 继续</span></div>';
    textLayer.appendChild(defaultBox);
    paragraphs = container.querySelectorAll('.text-box');
  }

  const interactionPanel = container.querySelector('.interaction-panel');
  const toggleBtn = container.querySelector('.toggle-btn');
  // ========================================

  // DOM元素缓存
  const elements = {
    textLayer,
    paragraphs,
    interactionPanel,
    toggleBtn
  };

  // === 高性能打字机效果 - 使用requestAnimationFrame ===
  function typeParagraph(element, text, onComplete) {
    if (!element || !text) return;

    state.isTyping = true;
    element.classList.add('typing');
    element.textContent = '';

    let index = 0;
    const totalChars = text.length;
    // 动态计算打字速度：根据文本长度调整，长文本适当加速
    const baseSpeed = Math.max(16, Math.min(35, 1000 / (totalChars * 0.5 + 10)));

    state.lastTypeTime = performance.now();

    function typeStep(currentTime) {
      if (!state.isTyping) return;

      const elapsed = currentTime - state.lastTypeTime;
      const charsToType = Math.max(1, Math.floor(elapsed / baseSpeed));

      if (index < totalChars) {
        // 批量添加字符减少重排
        const endIndex = Math.min(index + charsToType, totalChars);
        element.textContent = text.substring(0, endIndex);
        index = endIndex;
        state.lastTypeTime = currentTime;

        state.rafId = requestAnimationFrame(typeStep);
      } else {
        // 打字完成
        element.classList.remove('typing');
        element.classList.add('typing-complete');
        state.isTyping = false;
        state.rafId = null;
        if (onComplete) onComplete();
      }
    }

    state.rafId = requestAnimationFrame(typeStep);
  }

  // === 取消打字机效果 ===
  function cancelTyping() {
    if (state.rafId) {
      cancelAnimationFrame(state.rafId);
      state.rafId = null;
    }
    state.isTyping = false;
  }

  // === 段落切换逻辑 - 优化批量DOM操作 ===
  function showParagraph(index) {
    if (index >= elements.paragraphs.length) {
      checkInteractionTrigger();
      return;
    }

    elements.paragraphs.forEach((p, i) => {
      if (i === index) {
        p.style.display = 'block';
        p.classList.add('showing');

        const textEl = p.querySelector('.narrative-text');
        const fullText = textEl?.dataset.fulltext || '';

        // 延迟启动打字机，确保DOM已渲染
        requestAnimationFrame(() => {
          setTimeout(() => {
            typeParagraph(textEl, fullText, () => {
              // 打字完成，显示继续按钮
              const hint = p.querySelector('.continue-hint');
              if (hint) {
                requestAnimationFrame(() => {
                  hint.classList.add('visible');
                });
              }
            });
          }, 50);
        });
      } else if (i < index) {
        // 已显示的段落保持可见但移除动画类
        p.style.display = 'block';
        p.classList.remove('showing');
        const textEl = p.querySelector('.narrative-text');
        if (textEl && textEl.dataset.fulltext) {
          textEl.textContent = textEl.dataset.fulltext;
          textEl.classList.remove('typing');
        }
      } else {
        p.style.display = 'none';
        p.classList.remove('showing');
      }
    });

    state.currentParagraph = index;

    // 滚动到新段落（平滑滚动）
    if (elements.paragraphs[index]) {
      elements.paragraphs[index].scrollIntoView({ 
        behavior: 'smooth', 
        block: 'center' 
      });
    }
  }

  // === 检查交互触发 - 节流优化 ===
  let triggerCheckPending = false;
  function checkInteractionTrigger() {
    if (triggerCheckPending || state.interactionTriggered || !elements.interactionPanel) return;

    triggerCheckPending = true;
    requestAnimationFrame(() => {
      const trigger = elements.interactionPanel.dataset.trigger;
      const current = state.currentParagraph;
      const total = elements.paragraphs.length;

      let shouldTrigger = false;
      if (trigger === 'end' || trigger === String(current) || current >= total - 1) {
        shouldTrigger = true;
      }

      if (shouldTrigger) {
        state.interactionTriggered = true;
        elements.interactionPanel.classList.add('active');

        // 禁用所有继续按钮
        container.querySelectorAll('.continue-hint').forEach(h => {
          h.style.pointerEvents = 'none';
          h.style.opacity = '0.3';
        });
      }
      triggerCheckPending = false;
    });
  }

  // === 交互控件事件处理 - 防抖优化 ===
  function handleInteraction(e) {
    const btn = e.target.closest('[data-action]');
    if (!btn || btn.disabled) return;

    e.preventDefault();
    const action = btn.dataset.action;
    const value = btn.dataset.value || btn.textContent.trim();

    // 禁用所有控件防止重复
    const panel = btn.closest('.interaction-panel');
    if (panel) {
      panel.querySelectorAll('button, input').forEach(el => {
        el.disabled = true;
        if (el === btn) el.classList.add('selected');
      });
    }

    // 构造结果对象
    let result = {
      type: action,
      value: value,
      timestamp: Date.now(),
      sceneId: SCENE_ID
    };

    // 特殊处理
    if (action === 'dice') {
      const range = btn.dataset.range || '1-6';
      const [min, max] = range.split('-').map(Number);
      const roll = Math.floor(Math.random() * (max - min + 1)) + min;
      result.roll = roll;
      result.range = range;

      // 显示骰子动画
      const resultSpan = document.createElement('span');
      resultSpan.className = 'dice-result';
      resultSpan.textContent = `[${roll}]`;
      btn.appendChild(resultSpan);
    }

    if (action === 'dialogue') {
      const input = panel?.querySelector('.dialogue-input');
      if (input) {
        result.value = input.value.trim() || value;
        result.input = input.value.trim();
      }
    }

    if (action === 'timer') {
      const timeout = parseInt(btn.dataset.timeout) || 5;
      result.timeout = timeout;

      // 倒计时动画
      let remaining = timeout;
      const display = btn.querySelector('.timer-display');
      const timerId = setInterval(() => {
        remaining--;
        if (display) display.textContent = remaining + 's';
        if (remaining <= 0) {
          clearInterval(timerId);
          submitResult(result);
        }
      }, 1000);
      return; // 计时器自己处理提交
    }

    // 延迟提交以便显示反馈动画
    setTimeout(() => submitResult(result), action === 'dice' ? 600 : 300);
  }

  // === 提交结果到系统 ===
  function submitResult(result) {
    if (typeof window.__interactionResolver === 'function') {
      try {
        window.__interactionResolver(JSON.stringify(result));
      } catch (err) {
        console.error('[排版师] 回调调用失败:', err);
        showError('交互失败，请重试');
      }
    } else {
      console.error('[排版师] 未找到回调函数 window.__interactionResolver');
      showError('系统错误：无法返回结果');
    }
  }

  // === 错误提示 ===
  function showError(msg) {
    // 移除已存在的错误提示
    const existing = document.querySelector('.error-toast');
    if (existing) existing.remove();

    const toast = document.createElement('div');
    toast.className = 'error-toast';
    toast.textContent = msg;
    document.body.appendChild(toast);

    requestAnimationFrame(() => {
      setTimeout(() => toast.remove(), 3000);
    });
  }

  // === 隐藏/显示切换 - 使用RAF优化 ===
  function toggleVisibility() {
    if (!elements.textLayer) return;

    requestAnimationFrame(() => {
      elements.textLayer.classList.toggle('hidden');
      const isHidden = elements.textLayer.classList.contains('hidden');
      if (elements.toggleBtn) {
        elements.toggleBtn.textContent = isHidden ? '🙈' : '👁';
        elements.toggleBtn.style.opacity = isHidden ? '0.6' : '1';
      }
    });
  }

  // === 事件绑定 - 使用passive提升滚动性能 ===
  container.addEventListener('click', function(e) {
    // 继续按钮
    if (e.target.closest('.continue-hint')) {
      if (!state.isTyping) {
        showParagraph(state.currentParagraph + 1);
      } else {
        // 如果正在打字，点击则立即完成
        cancelTyping();
        const currentBox = elements.paragraphs[state.currentParagraph];
        if (currentBox) {
          const textEl = currentBox.querySelector('.narrative-text');
          if (textEl && textEl.dataset.fulltext) {
            textEl.textContent = textEl.dataset.fulltext;
            textEl.classList.remove('typing');
          }
          const hint = currentBox.querySelector('.continue-hint');
          if (hint) hint.classList.add('visible');
        }
      }
    }

    // 交互控件
    if (e.target.closest('.interaction-panel')) {
      handleInteraction(e);
    }

    // 隐藏按钮
    if (e.target.closest('.toggle-btn')) {
      toggleVisibility();
    }
  }, { passive: true });

  // 键盘支持
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Enter' || e.key === ' ') {
      const currentBox = elements.paragraphs[state.currentParagraph];
      if (!currentBox) return;

      const hint = currentBox.querySelector('.continue-hint');
      const isVisible = hint && hint.classList.contains('visible');

      if (isVisible && !state.isTyping) {
        e.preventDefault();
        showParagraph(state.currentParagraph + 1);
      }
    }
    if (e.key === 'Escape') {
      toggleVisibility();
    }
  });

  // === 初始化 - 使用IntersectionObserver优化可见性检测 ===
  function init() {
    if (state.typewriterDone) return;

    // 准备段落数据
    elements.paragraphs.forEach((box, idx) => {
      const textEl = box.querySelector('.narrative-text');
      if (textEl) {
        // 保存原文本到data属性
        if (!textEl.dataset.fulltext) {
          textEl.dataset.fulltext = textEl.textContent.trim();
        }
        // 初始隐藏继续按钮
        const hint = box.querySelector('.continue-hint');
        if (hint) hint.classList.remove('visible');
        // 只显示第一个
        if (idx > 0) box.style.display = 'none';
      }
    });

    // 开始第一个段落
    if (elements.paragraphs.length > 0) {
      const firstBox = elements.paragraphs[0];
      const firstText = firstBox.querySelector('.narrative-text');
      const text = firstText?.dataset.fulltext || '';

      // 使用RAF确保DOM就绪
      requestAnimationFrame(() => {
        setTimeout(() => {
          typeParagraph(firstText, text, () => {
            const hint = firstBox.querySelector('.continue-hint');
            if (hint) hint.classList.add('visible');
          });
        }, 300);
      });
    }

    state.typewriterDone = true;
    console.log('[排版师] 场景初始化完成:', SCENE_ID);
  }

  // 立即执行或等待DOM
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  // 清理函数（页面卸载时）
  window.addEventListener('beforeunload', () => {
    cancelTyping();
  });
})();
</script>
